css:
.loader, .loader:before, .loader:after {
  width: 35px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px inset currentColor;
   position: relative;
   animation: l6 1.5s infinite 0.5s;
}
.loader:before, .loader:after {
  content: "";
   position: absolute;
   left: calc(100% + 5px);
   animation-delay: 1s;
}
.loader:after {
  left: -40px;
   animation-delay: 0s;
}
@keyframes l6  {
  0%,55%,100% {border-radius:0 }
20%,30% {border-radius:50%}
}
